"use client";
import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { getUser } from '../lib/auth';
import { AlertTriangle, PhoneCall, MapPin } from 'lucide-react';

export default function DashboardCitizen() {
  const [user, setUser] = useState<any>(null);
  const [isChecking, setIsChecking] = useState(true);
  const router = useRouter();

  useEffect(() => {
    const currentUser = getUser();
    if (!currentUser || currentUser.role !== 'citizen') {
      router.push('/');
    } else {
      setUser(currentUser);
      setIsChecking(false);
    }
  }, [router]);

  if (isChecking || !user || user.role !== 'citizen') {
    return null;
  }

  return (
    <div className="min-h-[calc(100vh-4rem)] bg-slate-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-8">
          <h1 className="text-2xl sm:text-3xl font-bold text-slate-900">Welcome, {user.name}</h1>
          <p className="text-slate-600 mt-1">What is your emergency today?</p>
        </div>

        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
          <div className="bg-white overflow-hidden shadow-sm rounded-2xl border border-red-100 hover:border-red-300 transition-colors cursor-pointer group">
            <div className="p-6">
              <div className="flex items-center">
                <div className="flex-shrink-0 bg-red-100 rounded-xl p-3 group-hover:bg-red-200 transition-colors">
                  <AlertTriangle className="h-8 w-8 text-red-600" />
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dl>
                    <dt className="text-lg font-semibold text-slate-900 truncate">Report Emergency</dt>
                    <dd className="text-sm text-slate-500">Fire, Medical, or Police</dd>
                  </dl>
                </div>
              </div>
            </div>
            <div className="bg-red-50 px-6 py-3">
              <div className="text-sm font-medium text-red-700">Click to report immediately</div>
            </div>
          </div>

          <div className="bg-white overflow-hidden shadow-sm rounded-2xl border border-blue-100 hover:border-blue-300 transition-colors cursor-pointer group">
            <div className="p-6">
              <div className="flex items-center">
                <div className="flex-shrink-0 bg-blue-100 rounded-xl p-3 group-hover:bg-blue-200 transition-colors">
                  <MapPin className="h-8 w-8 text-blue-600" />
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dl>
                    <dt className="text-lg font-semibold text-slate-900 truncate">Nearby Services</dt>
                    <dd className="text-sm text-slate-500">Hospitals, Police Stations</dd>
                  </dl>
                </div>
              </div>
            </div>
            <div className="bg-blue-50 px-6 py-3">
              <div className="text-sm font-medium text-blue-700">View map</div>
            </div>
          </div>

          <div className="bg-white overflow-hidden shadow-sm rounded-2xl border border-amber-100 hover:border-amber-300 transition-colors cursor-pointer group">
            <div className="p-6">
              <div className="flex items-center">
                <div className="flex-shrink-0 bg-amber-100 rounded-xl p-3 group-hover:bg-amber-200 transition-colors">
                  <PhoneCall className="h-8 w-8 text-amber-600" />
                </div>
                <div className="ml-5 w-0 flex-1">
                  <dl>
                    <dt className="text-lg font-semibold text-slate-900 truncate">Emergency Contacts</dt>
                    <dd className="text-sm text-slate-500">Quick dial important numbers</dd>
                  </dl>
                </div>
              </div>
            </div>
            <div className="bg-amber-50 px-6 py-3">
              <div className="text-sm font-medium text-amber-700">View contacts</div>
            </div>
          </div>
        </div>

        <div className="mt-8">
          <h2 className="text-lg font-medium text-slate-900 mb-4">Your Recent Reports</h2>
          <div className="bg-white shadow-sm rounded-2xl border border-slate-200 overflow-hidden">
            <div className="p-6 text-center text-slate-500">
              You haven't made any emergency reports yet.
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
